// --- Helpers ------------------------------------------------------------

export function groupRowsBySubProcess(rows: ProcurementRacmRow[]): { subProcess: string; rows: ProcurementRacmRow[] }[] {
  const map = new Map<string, ProcurementRacmRow[]>();
  for (const r of rows) {
    const key = r.subProcess || "(Unassigned)";
    if (!map.has(key)) map.set(key, []);
    map.get(key)!.push(r);
  }
  return Array.from(map.entries()).map(([subProcess, rows]) => ({ subProcess, rows }));
}

export function deriveRiskRatingClass(rating: string): string {
  const r = (rating || '').toLowerCase();
  if (r === 'high' || r === 'critical') return 'bg-red-50 text-red-700 border-red-100';
  if (r === 'medium') return 'bg-amber-50 text-amber-700 border-amber-100';
  if (r === 'low') return 'bg-emerald-50 text-emerald-700 border-emerald-100';
  return 'bg-gray-100 text-gray-600 border-gray-200';
}

export function deriveControlTypeClass(type: string): string {
  if (type === 'Preventive') return 'bg-emerald-50 text-emerald-700 border-emerald-100';
  if (type === 'Detective') return 'bg-blue-50 text-blue-700 border-blue-100';
  if (type === 'Corrective') return 'bg-purple-50 text-purple-700 border-purple-100';
  return 'bg-gray-100 text-gray-600 border-gray-200';
}

export function deriveControlNatureClass(nature: string): string {
  if (nature === 'Manual') return 'bg-amber-50 text-amber-700 border-amber-100';
  if (nature === 'Automated') return 'bg-emerald-50 text-emerald-700 border-emerald-100';
  if ((nature || '').toLowerCase().includes('hybrid')) return 'bg-blue-50 text-blue-700 border-blue-100';
  return 'bg-gray-100 text-gray-600 border-gray-200';
}